mapper.select:
SELECT dd.id, dd.value, dd.label, dd.description, dd.created_at, creator.username AS creator, dd.updated_at, COALESCE(updater.username, 'Unknown') AS updater FROM sys_dict_data dd LEFT JOIN sys_user creator ON dd.created_by = creator.id LEFT JOIN sys_user updater ON dd.updated_by = updater.id
AND dd.type_id = #{dictTypeId}
${ew.customSqlSegment}
